import { ZuploContext, ZuploRequest, ZuploHeaders } from "@zuplo/runtime";

/**
 * Custom inbound policy that validates JWT tokens using HMAC SHA-256.
 * Reads the JWT_SECRET from environment variables.
 * If the token is valid, the request proceeds.
 * If the token is missing, malformed, or has an invalid signature,
 * the request is rejected with 401 Unauthorized.
 */
export default async function (request: ZuploRequest, context: ZuploContext) {
  const authHeader = request.headers.get("Authorization");

  if (!authHeader) {
    return new Response(
      JSON.stringify({ error: "Unauthorized: Missing Authorization header" }),
      {
        status: 401,
        headers: { "Content-Type": "application/json" },
      }
    );
  }

  // Extract Bearer token
  const parts = authHeader.split(" ");
  if (parts.length !== 2 || parts[0] !== "Bearer") {
    return new Response(
      JSON.stringify({ error: "Unauthorized: Malformed Authorization header" }),
      {
        status: 401,
        headers: { "Content-Type": "application/json" },
      }
    );
  }

  const token = parts[1];

  // Validate the JWT signature
  const isValid = await verifyJwtHmacSha256(token, context.env.JWT_SECRET);

  if (!isValid) {
    return new Response(
      JSON.stringify({ error: "Unauthorized: Invalid token" }),
      {
        status: 401,
        headers: { "Content-Type": "application/json" },
      }
    );
  }

  // Token is valid, allow request to proceed
  return request;
}

/**
 * Verifies a JWT token signed with HMAC SHA-256 using the Web Crypto API.
 */
async function verifyJwtHmacSha256(
  token: string,
  secret: string
): Promise<boolean> {
  try {
    // Split the JWT into its parts
    const parts = token.split(".");
    if (parts.length !== 3) {
      return false;
    }

    const [headerB64, payloadB64, signatureB64] = parts;

    // Import the secret key
    const encoder = new TextEncoder();
    const key = await crypto.subtle.importKey(
      "raw",
      encoder.encode(secret),
      { name: "HMAC", hash: "SHA-256" },
      false,
      ["verify"]
    );

    // Compute the expected signature
    const signingInput = `${headerB64}.${payloadB64}`;
    const signature = base64UrlDecode(signatureB64);

    // Verify the signature
    const valid = await crypto.subtle.verify(
      "HMAC",
      key,
      signature,
      encoder.encode(signingInput)
    );

    return valid;
  } catch {
    return false;
  }
}

/**
 * Decodes a Base64URL-encoded string to a Uint8Array.
 */
function base64UrlDecode(str: string): Uint8Array {
  // Replace Base64URL characters with standard Base64 characters
  let base64 = str.replace(/-/g, "+").replace(/_/g, "/");

  // Add padding if necessary
  const pad = base64.length % 4;
  if (pad === 2) {
    base64 += "==";
  } else if (pad === 3) {
    base64 += "=";
  }

  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

